import { AgentServiceClient } from '@azure/ai-projects';
import { VexTokenMonitor } from 'vex-sdk';

const client = new AgentServiceClient({
  endpoint: 'https://your-project.openai.azure.com/',
  apiKey: process.env.AZURE_API_KEY
});

const tokenMonitor = new VexTokenMonitor({
  maxTokens: 128000,
  model: 'gpt-4o'
});

async function debugCodebase(threadId: string, userQuery: string) {
  let thread = await client.getThread(threadId);

  // Check token limits before adding messages
  if (await tokenMonitor.check(thread)) {
    await tokenMonitor.summarizeThread(thread);
  }

  const message = await client.sendMessage(threadId, {
    role: 'user',
    content: userQuery
  });

  return message;
}

import { ContainerInstanceClient } from '@azure/container-instance';
import { DependencyGuard } from 'vex-sdk';

const containerClient = new ContainerInstanceClient(/* config */);
const depGuard = new DependencyGuard();

async function safeExecute(code: string, requirements: string[]) {
  // Scan dependencies first
  const safeDeps = await depGuard.scan(requirements, {
    policies: ['vulnerability_free', 'license_compliant']
  });

  if (!safeDeps.approved) {
    throw new Error('Dependencies failed security scan');
  }

  // Execute in sandbox
  const container = await containerClient.createContainerGroup({
    image: 'python:3.11-slim',
    command: ['python', '-c', code],
    environmentVariables: safeDeps.packages
  });

  return await container.waitForCompletion();
}

